<?php

namespace Modules\Theme\Controllers;

class Theme extends \Modules\Backend\Controllers\BaseController
{
    public function index()
    {
        helper('modules/Theme/Helpers/theme_helper');
        return view('Modules\Theme\Views\index', $this->defData);
    }

    public function upload()
    {
        $valData = ([
            'theme' => ['label' => lang('Theme.backendTheme'), 'rules' => 'uploaded[theme]|ext_in[theme,zip]|mime_in[theme,application/x-zip,application/zip,application/x-zip-compressed,application/s-compressed,multipart/x-zip]'],
        ]);
        if ($this->validate($valData) == false) return redirect()->route('backendThemes')->withInput()->with('errors', $this->validator->getErrors());
        $file = $this->request->getFile('theme');
        $tempPath = WRITEPATH . 'tmp/' . str_replace('_theme.zip', '', $file->getName()) . '/';
        $zip = new \ZipArchive();
        if ($zip->open($file->getTempName()) === true) {
            $zip->extractTo($tempPath);
            $zip->close();
        } else {
            return redirect()->route('backendThemes')->withInput()->with('errors', [lang('Theme.zipOpenFailed')]);
        }

        $themeName = str_replace('_theme.zip', '', $file->getName());
        $paths = [
            APPPATH . "Config/templates/" . $themeName,
            APPPATH . "Controllers/templates/" . $themeName,
            APPPATH . "Helpers/templates/" . $themeName,
            APPPATH . "Libraries/templates/" . $themeName,
            APPPATH . "Views/templates/" . $themeName,
            ROOTPATH . "public/templates/" . $themeName
        ];
        helper('Modules\Theme\Helpers\themes');
        $duplicates = findDuplicateSubfolders($paths);
        if (!empty($duplicates)) {
            echo lang('Theme.foldersWithSameNameHeader');
            foreach ($duplicates as $folder => $dirs) {
                echo lang('Theme.foldersWithSameNameMessage', [$folder]);
                foreach ($dirs as $dir) {
                    echo lang('Install.foldersWithSameNameListItem', [$dir]);
                }
                echo "</ul>";
            }
            deleteFldr(rtrim($tempPath, '/'));
        } else {
            $log = install_theme_from_tmp($themeName);
            deleteFldr(rtrim($tempPath, '/'));
            return redirect()->route('backendThemes')->with('log', $log);
        }

    }

    public function deleteConfirm(string $slug)
    {
        $themeName = $slug;
        $activeTheme = setting('App.siteTheme'); // aktif temayı engelle
        if ($activeTheme === $themeName) {
            return redirect()->route('templateSettings')->with('errors', [lang('Theme.themeActiveCannotDelete')]);
        }

        $tables = [];
        $migrationPath = APPPATH . 'Database/Migrations/templates/' . $themeName;
        if (is_dir($migrationPath)) {
            $files = glob($migrationPath . '/*.php');
            if ($files !== false) {
                foreach ($files as $file) {
                    $content = file_get_contents($file);
                    preg_match_all("/\\\$this->forge->createTable\s*\(\s*['\"]([^'\"]+)['\"]/i", $content, $matches);
                    if (!empty($matches[1])) {
                        // Eğer array gelirse her birini tablolara at
                        foreach ($matches[1] as $tableName) {
                            $tables[] = $tableName;
                        }
                    }
                }
            }
        }

        $this->defData['themeName'] = $themeName;
        $this->defData['tables'] = array_unique($tables);

        return view('Modules\Theme\Views\delete_confirm', $this->defData);
    }

    public function deleteProcess(string $slug)
    {
        $themeName = $slug;
        $activeTheme = setting('App.siteTheme');
        if ($activeTheme === $themeName) {
            return redirect()->route('templateSettings')->with('errors', [lang('Theme.themeActiveCannotDelete')]);
        }

        $log = [];
        // Tabloları sil (seçilenler)
        $tablesToDrop = $this->request->getPost('tables');
        if (!empty($tablesToDrop) && is_array($tablesToDrop)) {
            $forge = \Config\Database::forge();
            $db = \Config\Database::connect();
            foreach ($tablesToDrop as $table) {
                if ($db->tableExists($table)) {
                    $forge->dropTable($table, true);
                    $log[] = "🗑️ Tablo silindi: $table";
                }
            }
        }

        helper('Modules\Theme\Helpers\themes');
        // remove_theme_files (eğer helper yüklenmemişse hata vermemesi için function_exists kontrolü)
        if (function_exists('remove_theme_files')) {
            $removeLogs = remove_theme_files($themeName);
            $log = array_merge($log, $removeLogs);
        }

        return redirect()->route('settings')->with('messages', $log);
    }

    public function downloadStarter()
    {
        $zipPath = WRITEPATH . 'starter_theme.zip';

        if (!file_exists($zipPath)) {
            $zip = new \ZipArchive();
            if ($zip->open($zipPath, \ZipArchive::CREATE | \ZipArchive::OVERWRITE) === TRUE) {
                $zip->addEmptyDir('app');
                $zip->addEmptyDir('app/Config');
                $zip->addEmptyDir('app/Config/templates');
                $zip->addEmptyDir('app/Config/templates/starter');
                $zip->addEmptyDir('app/Libraries');
                $zip->addEmptyDir('app/Libraries/templates');
                $zip->addEmptyDir('app/Libraries/templates/starter');
                $zip->addEmptyDir('app/Controllers');
                $zip->addEmptyDir('app/Controllers/templates');
                $zip->addEmptyDir('app/Controllers/templates/starter');
                $zip->addEmptyDir('app/Views');
                $zip->addEmptyDir('app/Views/templates');
                $zip->addEmptyDir('app/Views/templates/starter');
                $zip->addEmptyDir('app/Views/templates/starter/blog');
                $zip->addEmptyDir('app/Views/templates/starter/widgets');
                $zip->addEmptyDir('app/Helpers');
                $zip->addEmptyDir('app/Helpers/templates');
                $zip->addEmptyDir('app/Helpers/templates/starter');
                $zip->addEmptyDir('public');
                $zip->addEmptyDir('public/templates');
                $zip->addEmptyDir('public/templates/starter');
                $zip->addEmptyDir('public/templates/starter/assets');
                $zip->addEmptyDir('public/templates/starter/assets/vendor');
                $zip->addEmptyDir('public/templates/starter/assets/vendor/popperjs');
                $zip->addEmptyDir('public/templates/starter/assets/vendor/bootstrap');
                $zip->addEmptyDir('public/templates/starter/assets/vendor/modern-business');
                $zip->addEmptyDir('public/templates/starter/assets/vendor/sweetalert2');
                $zip->addEmptyDir('public/templates/starter/assets/vendor/jquery');

                $base64Files = [
                    'app/Config/templates/starter/ThemeConfig.php' => '',
                    'app/Config/templates/starter/Routes.php' => '',
                    'app/Libraries/templates/starter/Ci4mstemplateLib.php' => '',
                    'app/Controllers/templates/starter/Forms.php' => '',
                    'app/Views/templates/starter/temp-settings.php' => '',
                    'app/Views/templates/starter/base.php' => '',
                    'app/Views/templates/starter/pages.php' => '',
                    'app/Helpers/templates/starter/funcs_helper.php' => '',
                    'public/templates/starter/info.xml' => '',
                    'public/templates/starter/screenshot.png' => ''
                ];

                foreach ($base64Files as $path => $b64content) {
                    $zip->addFromString($path, base64_decode($b64content));
                }

                $zip->close();
            } else {
                return redirect()->back()->with('errors', [lang('Theme.zipOpenFailed')]);
            }
        }

        return $this->response->download($zipPath, null)->setFileName('starter_theme.zip');
    }
}
